import numpy as np

class GaussianNB:
 def __init__(self):
 self.classes = None
 self.mean = {} # {class: [mean_f1, mean_f2, ...]}
 self.var = {} # {class: [var_f1, var_f2, ...]}
 self.priors = {} # {class: prior_probability}

 def fit(self, X, y):
 n_samples, n_features = X.shape
 self.classes = np.unique(y)

 for c in self.classes:
 X_c = X[y == c]
 self.mean[c] = np.mean(X_c, axis=0)
 self.var[c] = np.var(X_c, axis=0) + 1e-9 # smoothing
 self.priors[c] = X_c.shape[0] / n_samples

 def _gaussian_pdf(self, X, mean, var):
 coeff = 1 / np.sqrt(2 * np.pi * var)
 exponent = -((X - mean) ** 2) / (2 * var)
 return coeff * np.exp(exponent)

 def predict(self, X):
 predictions = []
 for x in X:
 posteriors = {}
 for c in self.classes:
 # Log for numerical stability
 log_prior = np.log(self.priors[c])
 log_likelihood = np.sum(np.log(self._gaussian_pdf(x, self.mean[c], self.var[c])))
 posteriors[c] = log_prior + log_likelihood
 predictions.append(max(posteriors, key=posteriors.get))
 return np.array(predictions)

import numpy as np
from scipy.stats import norm

def gaussian_pdf(x, mu, sigma_sq):
 """Compute Gaussian probability density at x"""
 coeff = 1.0 / np.sqrt(2 * np.pi * sigma_sq)
 exponent = -((x - mu) ** 2) / (2 * sigma_sq)
 return coeff * np.exp(exponent)

def predict_with_probabilities(X_test, mu, sigma_sq, priors):
 """
 mu, sigma_sq: dicts {class: [values per feature]}
 priors: dict {class: prior probability}
 """
 predictions = []
 probabilities = []

 for x in X_test:
 posteriors = {}
 for c in priors.keys():
 # Compute log-likelihood for numerical stability
 log_likelihood = 0
 for j in range(len(x)):
 pdf_val = gaussian_pdf(x[j], mu[c][j], sigma_sq[c][j])
 log_likelihood += np.log(pdf_val + 1e-300)

 # Log posterior = log likelihood + log prior
 log_posterior = log_likelihood + np.log(priors[c])
 posteriors[c] = log_posterior

 # Normalize using log-sum-exp trick
 max_log = max(posteriors.values())
 sum_exp = sum(np.exp(v - max_log) for v in posteriors.values())
 log_normalizer = max_log + np.log(sum_exp)

 # Convert back from log and normalize
 probs = {c: np.exp(v - log_normalizer) for c, v in posteriors.items()}
 predictions.append(max(probs, key=probs.get))
 probabilities.append(probs)

 return predictions, probabilities

# Example usage
mu = {'spam': [10.0, 50.0], 'ham': [2.0, 10.0]}
sigma_sq = {'spam': [4.0, 100.0], 'ham': [1.0, 25.0]}
priors = {'spam': 0.3, 'ham': 0.7}
X_test = np.array([[8, 40], [3, 15], [12, 80]])

preds, probs = predict_with_probabilities(X_test, mu, sigma_sq, priors)
print("Predictions:", preds)
print("Probabilities:", probs)
